javascript:(function(){const GITHUB_TOKEN="ghp_YOUR_TOKEN_HERE",GITHUB_OWNER="karthikeyankc",GITHUB_REPO="picks",CONFIG_URL=`https://raw.githubusercontent.com/${GITHUB_OWNER}/picks/main/config.json`,INDEX_URL=`https://raw.githubusercontent.com/${GITHUB_OWNER}/picks/main/index.json`;!function(){if(document.getElementById("__picks-overlay"))return;function e(e){const t=document.querySelector(`meta[property="og:${e}"], meta[name="${e}"]`);return t&&t.getAttribute("content")||""}const t=location.href,n=e("title")||document.title||"",i=e("description")||"",o=e("image")||"";const a=(new Date).toISOString().slice(0,10),c=document.createElement("style");c.textContent=`
    #__picks-overlay{position:fixed;inset:0;z-index:2147483647;display:flex;align-items:center;justify-content:center;background:rgba(0,0,0,.45);font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif}
    #__picks-box{background:#fff;border-radius:12px;padding:24px;width:420px;max-width:calc(100vw - 32px);box-shadow:0 8px 40px rgba(0,0,0,.22);display:flex;flex-direction:column;gap:12px}
    #__picks-box h2{margin:0;font-size:14px;font-weight:700;color:#111;letter-spacing:-.01em}
    #__picks-box label{font-size:12px;font-weight:600;color:#555;display:block;margin-bottom:3px}
    #__picks-box input,#__picks-box select,#__picks-box textarea{width:100%;box-sizing:border-box;padding:7px 10px;border:1px solid #ddd;border-radius:7px;font-size:13px;color:#111;background:#fafafa;outline:none}
    #__picks-box input:focus,#__picks-box select:focus,#__picks-box textarea:focus{border-color:#6366f1;background:#fff}
    #__picks-box textarea{resize:vertical;min-height:56px}
    #__picks-box .__picks-row{display:flex;gap:8px}
    #__picks-box .__picks-row>div{flex:1}
    #__picks-box .__picks-actions{display:flex;gap:8px;margin-top:4px}
    #__picks-btn-save{flex:1;padding:9px;background:#111;color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:600;cursor:pointer}
    #__picks-btn-save:hover{background:#333}
    #__picks-btn-save:disabled{background:#999;cursor:not-allowed}
    #__picks-btn-cancel{padding:9px 16px;background:#f3f4f6;color:#555;border:none;border-radius:8px;font-size:13px;cursor:pointer}
    #__picks-status{font-size:12px;color:#555;text-align:center;min-height:16px}
    #__picks-archive{font-size:11px;color:#aaa;word-break:break-all}
    #__picks-edit-badge{display:inline-block;font-size:11px;font-weight:600;background:#fef3c7;color:#92400e;padding:2px 8px;border-radius:5px}
    .__picks-tag-chip{display:inline-block;padding:2px 9px;border:1px solid #e0e0e0;border-radius:5px;font-size:11px;background:#f5f5f5;color:#555;cursor:pointer;user-select:none;font-family:inherit}
    .__picks-tag-chip.active{background:#111;color:#fff;border-color:#111}
    .__picks-tag-chip:hover:not(.active){background:#eee}
  `,document.head.appendChild(c);const s=document.createElement("div");s.id="__picks-overlay",s.innerHTML=`
    <div id="__picks-box">
      <h2>+ Pick <span id="__picks-edit-badge" style="display:none">editing</span></h2>
      <div><label>Title</label><input id="__p-title" value="${n.replace(/"/g,"&quot;")}" /></div>
      <div><label>URL</label><input id="__p-url" value="${t.replace(/"/g,"&quot;")}" /></div>
      <div><label>Description</label><textarea id="__p-desc">${i}</textarea></div>
      <div class="__picks-row">
        <div><label>Category</label><select id="__p-category"><option value="">Loading…</option></select></div>
        <div>
          <label>Tags <span style="font-weight:400;color:#aaa">(comma separated)</span></label>
          <input id="__p-tags" placeholder="type or pick below" autocomplete="off" />
          <div id="__p-tags-suggest" style="display:flex;flex-wrap:wrap;gap:5px;margin-top:6px"></div>
        </div>
      </div>
      <div><label>Note <span style="font-weight:400;color:#aaa">(optional)</span></label><textarea id="__p-note" style="min-height:42px" placeholder="Why this stuck."></textarea></div>
      <div id="__picks-archive">Checking Wayback Machine…</div>
      <div class="__picks-actions"><button id="__picks-btn-cancel">Cancel</button><button id="__picks-btn-save">Save pick</button></div>
      <div id="__picks-status"></div>
    </div>
  `,document.body.appendChild(s);
  function syncChips(){const cur=document.getElementById("__p-tags").value.split(",").map(t=>t.trim()).filter(Boolean);document.querySelectorAll(".__picks-tag-chip").forEach(c=>c.classList.toggle("active",cur.includes(c.dataset.tag)))}
  document.getElementById("__p-tags").addEventListener("input",syncChips);
  document.getElementById("__p-tags-suggest").addEventListener("click",e=>{const chip=e.target.closest(".__picks-tag-chip");if(!chip)return;const tag=chip.dataset.tag,inp=document.getElementById("__p-tags"),cur=inp.value.split(",").map(t=>t.trim()).filter(Boolean),idx=cur.indexOf(tag);if(idx>-1)cur.splice(idx,1);else cur.push(tag);inp.value=cur.join(", ");syncChips()});
  fetch(CONFIG_URL+"?t="+Date.now()).then(e=>e.ok?e.json():{categories:["art","tech","science","philosophy","writing","life"]}).then(cfg=>{const sel=document.getElementById("__p-category");if(sel)sel.innerHTML=(cfg.categories||[]).map(c=>`<option value="${c}">${c}</option>`).join("");const sg=document.getElementById("__p-tags-suggest");if(sg&&cfg.tags&&cfg.tags.length>0){sg.innerHTML=cfg.tags.map(t=>`<button type="button" class="__picks-tag-chip" data-tag="${t}">${t}</button>`).join("");syncChips()}}).catch(()=>{const sel=document.getElementById("__p-category");if(sel)sel.innerHTML=["art","tech","science","philosophy","writing","life"].map(c=>`<option value="${c}">${c}</option>`).join("")});
  let d=null;fetch(INDEX_URL+"?t="+Date.now()).then(e=>e.ok?e.json():[]).then(e=>{const x=e.find(e=>e.url===t);if(x&&(d=x.id,document.getElementById("__p-title").value=x.title||"",document.getElementById("__p-desc").value=x.description||"",document.getElementById("__p-note").value=x.note||"",document.getElementById("__p-tags").value=(x.tags||[]).join(", "),syncChips(),document.getElementById("__picks-btn-save").textContent="Update pick",document.getElementById("__picks-edit-badge").style.display="inline-block",x.category)){const sel=document.getElementById("__p-category");[...sel.options].find(o=>o.value===x.category)&&(sel.value=x.category)}}).catch(()=>{});
  let p="";fetch(`https://archive.org/wayback/available?url=${encodeURIComponent(t)}`).then(e=>e.json()).then(e=>{const sn=e.archived_snapshots&&e.archived_snapshots.closest;sn&&sn.available?(p=sn.url,document.getElementById("__picks-archive").textContent=`Archive: ${p}`):(p=`https://web.archive.org/save/${t}`,fetch(p).catch(()=>{}),document.getElementById("__picks-archive").textContent="No snapshot found — archiving now.")}).catch(()=>{document.getElementById("__picks-archive").textContent="Could not reach Wayback Machine."});
  document.getElementById("__picks-btn-cancel").onclick=()=>s.remove();s.addEventListener("click",e=>{e.target===s&&s.remove()});
  document.getElementById("__picks-btn-save").onclick=async function(){const btn=this,status=document.getElementById("__picks-status"),title=document.getElementById("__p-title").value.trim(),url=document.getElementById("__p-url").value.trim(),desc=document.getElementById("__p-desc").value.trim(),cat=document.getElementById("__p-category").value,tags=document.getElementById("__p-tags").value.split(",").map(t=>t.trim()).filter(Boolean),note=document.getElementById("__p-note").value.trim();if(!title||!url)return void(status.textContent="Title and URL are required.");function slugify(str){return str.toLowerCase().replace(/[^a-z0-9]+/g,"-").replace(/^-|-$/g,"").slice(0,60)}const id=d||`${a}-${slugify(title)}`,date=d?id.slice(0,10):a,pick={id,url,title,description:desc,category:cat,tags,date,note,image:o,archive_url:p};pick.note||delete pick.note;pick.image||delete pick.image;pick.archive_url||delete pick.archive_url;const filePath=`picks/${id}.json`,content=btoa(unescape(encodeURIComponent(JSON.stringify(pick,null,2))));btn.disabled=!0;status.textContent=d?"Updating…":"Saving…";try{let sha;const chk=await fetch(`https://api.github.com/repos/${GITHUB_OWNER}/picks/contents/${filePath}`,{headers:{Authorization:`Bearer ${GITHUB_TOKEN}`,Accept:"application/vnd.github+json"}});if(chk.ok){sha=(await chk.json()).sha}const body={message:d?`edit: ${title}`:`pick: ${title}`,content};if(sha)body.sha=sha;const res=await fetch(`https://api.github.com/repos/${GITHUB_OWNER}/picks/contents/${filePath}`,{method:"PUT",headers:{Authorization:`Bearer ${GITHUB_TOKEN}`,Accept:"application/vnd.github+json","Content-Type":"application/json"},body:JSON.stringify(body)});if(res.ok){status.textContent=d?"✓ Updated.":"✓ Saved.";btn.textContent=d?"Updated ✓":"Saved ✓";setTimeout(()=>s.remove(),1600)}else{const err=await res.json();status.textContent=`Error: ${err.message}`;btn.disabled=!1}}catch(err){status.textContent=`Network error: ${err.message}`;btn.disabled=!1}}}()})();
